// Wrapping a callback API in a Promise
function delay(ms) {
  return new Promise((resolve, reject) => {
    if (ms < 0) {
      reject(new Error('Delay cannot be negative')); // Trigger failure
    } else {
      setTimeout(() => {
        resolve(`Waited ${ms} milliseconds`);      // Trigger success
      }, ms);
    }
  });
}

delay(1000)
  .then(msg => console.log('Success:', msg))
  .catch(err => console.error('Error:', err.message));

delay(-500)
  .then(msg => console.log('Success:', msg))
  .catch(err => console.error('Error:', err.message)); // Catches the rejection

