const innerPromise = new Promise(res => setTimeout(() => res('Inner data!'), 1000));

const outerPromise = new Promise(resolve => {
  resolve(innerPromise); // Outer promise waits for innerPromise
});

outerPromise.then(val => console.log(val)); // 'Inner data!' after 1 sec
